@spec timing_atoms_spec  src=tests/specs/timing_atoms_spec.lua  loc=363  sha=4a6bfb0  cases=19
@exercises timing (timing)
@surface   timing.resolveFactors, timing.applyFactors, timing.unapplyFactors, timing.atomTilePeriod, timing.logPerRow

# Intent
  Atoms are pure unit-interval functions {forward, inverse}. forward
  pins endpoints (id excepted), is monotone on [0,1] for in-range
  shift, and inverse closes the round-trip to machine precision via
  Newton iteration. resolveFactors lifts atoms to a tiled
  ResolvedFactor[]; applyFactors / unapplyFactors consume it.

# Cases
  @case 'atomTilePeriod doubles for lilt and pocket, passes through for the rest'  [pure]  @ 42-51
  @case 'forward(u, 0) = u for every atom (zero-shift identity)'  [pure]  @ 57-66
  @case 'smooth atoms pin endpoints: forward(0, s) = 0 and forward(1, s) = 1'  [pure]  @ 70-82
  @case 'id forward shifts; inverse undoes it'  [pure]  @ 86-97
  @case 'smooth inverses close the round-trip to machine precision'  [pure]  @ 101-119
  @case 'forward is strictly monotone on [0, 1] for in-range shift'  [pure]  @ 123-142
  @case 'analytic slope stays within [1/K, K] at max in-range shift'  [pure]  @ 146-169
  @case 'principal lands at nominal + shift, atom-independent'  [pure]  @ 175-191
  @case 'shift is period-decoupled: same shift, different periods, both land shift away'  [pure]  @ 195-203
  @case 'classic-58 preset matches the legacy 0.58 mapping'  [pure]  @ 207-211
  @case 'identity atom shift = 0: pass-through'  [pure]  @ 215-222
  @case 'identity atom shift ≠ 0: constant output translation, period-scaled'  [pure]  @ 226-244
  @case 'identity atom shift ≠ 0: apply/unapply round-trip'  [pure]  @ 248-257
  @case 'per-factor phase: shifts the fixed-point lattice from {kT} to {phase + kT}'  [pure]  @ 263-274
  @case 'per-factor phase: apply/unapply round-trip'  [pure]  @ 278-287
  @case 'per-factor phase: phase = nil and phase = 0 are equivalent'  [pure]  @ 291-303
  @case 'K constant is exposed and atom ranges are derived from it'  [pure]  @ 309-334
  @case 'existing presets stay within their K-bounded atom ranges'  [pure]  @ 338-351
  @case 'logPerRow handles non-divisor rpbs (returns float, no truncation)'  [pure]  @ 357-361

# Uses (outbound edges)
